INSERT INTO gejala (id, kode, pertanyaan, kategori) VALUES
('g001', 'G001', 'Apakah laptop/PC sama sekali tidak menyala ketika tombol power ditekan?', 'power'),
('g002', 'G002', 'Apakah lampu indikator daya (power LED) tidak menyala sama sekali?', 'power'),
('g003', 'G003', 'Apakah lampu indikator pengisian baterai tidak menyala saat charger dicolokkan?', 'power'),
('g004', 'G004', 'Apakah laptop mati mendadak tanpa peringatan saat sedang digunakan?', 'power'),
('g005', 'G005', 'Apakah laptop restart sendiri berulang kali secara tiba-tiba?', 'power'),
('g006', 'G006', 'Apakah adaptor/charger terasa sangat panas tidak normal?', 'power'),
('g007', 'G007', 'Apakah adaptor/charger tidak mengeluarkan output tegangan (dicek dengan multimeter)?', 'power'),
('g008', 'G008', 'Apakah laptop tidak menyala meski sudah diganti dengan adaptor lain yang kompatibel?', 'power'),
('g009', 'G009', 'Apakah baterai tidak terdeteksi oleh sistem operasi (tidak ada ikon baterai)?', 'baterai'),
('g010', 'G010', 'Apakah persentase baterai tidak bertambah sama sekali meski charger terpasang lama?', 'baterai'),
('g011', 'G011', 'Apakah baterai turun sangat cepat (habis dalam < 30 menit dari kondisi penuh)?', 'baterai'),
('g012', 'G012', 'Apakah baterai terlihat menggembung (swollen/bloated)?', 'baterai'),
('g013', 'G013', 'Apakah laptop hanya bisa menyala jika kabel charger terpasang (tanpa baterai tidak bisa)?', 'baterai'),
('g014', 'G014', 'Apakah layar sama sekali tidak menampilkan gambar (blank/hitam total)?', 'display'),
('g015', 'G015', 'Apakah layar menampilkan gambar tetapi sangat redup atau tidak ada cahaya backlight?', 'display'),
('g016', 'G016', 'Apakah ada garis-garis horizontal atau vertikal pada layar?', 'display'),
('g017', 'G017', 'Apakah layar berkedip-kedip (flickering) saat digunakan?', 'display'),
('g018', 'G018', 'Apakah ada area layar yang memiliki warna berbeda, bercak, atau dead pixel?', 'display'),
('g019', 'G019', 'Apakah gambar tampil normal ketika laptop dihubungkan ke monitor eksternal?', 'display'),
